template <class T, class U>
inline bool chmin(T &a, U b) {
    if (a > b) {
        a = b;
        return true;
    }
    return false;
}
template <class T, class U>
inline bool chmax(T &a, U b) {
    if (a < b) {
        a = b;
        return true;
    }
    return false;
}
using namespace std;

struct UnionFind {
    int N;
    vector<int> siz,par;
    int find(int x) { return (par[x] == x ? x : par[x] = find(par[x])); }
    void merge(int x, int y) {
        x = find(x), y = find(y);
        if (x == y) return;
        if (siz[x] > siz[y]) swap(x, y);
        par[x] = y;
        siz[y] += siz[x];
    }
    UnionFind(int N) : N(N), siz(N, 1), par(N) {
        iota(par.begin(), par.end(), 0);
    }
};

// 方向を表す
int dx[] = {-1, 0, 1, 0}, dy[] = {0, 1, 0, -1};

// 操作
struct Act {
    int type, x, y;
};

struct Game {
    vector<vector<bool>> C;
    vector<vector<bool>> wall_hrz, wall_vert;
    vector<int> X, Y, wall_used, score;
    bool is_finished = false;

    int MAX_WALL = 10;
    int turn = 0,myturn = 0;
    int turn_num = 0;
    vector<Act> acts;

    // 連結性が保たれているかの判定
    // todo!
    bool isConnected() {
        UnionFind uf(81);
        rep(i, 9) rep(j, 9) {
            if (i < 8 && !wall_hrz[i][j]) uf.merge(i * 9 + j, (i + 1) * 9 + j);
            if (j < 8 && !wall_vert[i][j]) uf.merge(i * 9 + j, i * 9 + j + 1);
        }
        return uf.siz[uf.find(0)] == 81;
    }

    // 操作が適正であるかの判定
    bool isOK(Act act) {
        if (act.type == 0) {
            if (act.x == 0)  // 上
                return X[turn] && !wall_hrz[X[turn] - 1][Y[turn]];
            else if (act.x == 1)  // 右
                return Y[turn] != 8 && !wall_vert[X[turn]][Y[turn]];
            else if (act.x == 2)  // 下
                return X[turn] != 8 && !wall_hrz[X[turn]][Y[turn]];
            else if (act.x == 3)  // 左
                return Y[turn] && !wall_vert[X[turn]][Y[turn] - 1];
            else
                return false;
        } else if (act.type == 1) {
            if (act.x < 0 || act.x > 7 || act.y < 0 || act.y > 7) return false;
            if (wall_used[turn] == MAX_WALL)
                return false;  // 11 回目に置こうとしたらアウト
            if (wall_hrz[act.x][act.y] ||
                wall_hrz[act.x][act.y + 1])  // 既に置かれていたらアウト
                return false;
            wall_hrz[act.x][act.y] = wall_hrz[act.x][act.y + 1] = true;
            bool res = isConnected();  // 連結性チェック
            wall_hrz[act.x][act.y] = wall_hrz[act.x][act.y + 1] = false;
            return res;
        } else if (act.type == 2) {
            if (act.x < 0 || act.x > 7 || act.y < 0 || act.y > 7) return false;
            if (wall_used[turn] == MAX_WALL) return false;
            if (wall_vert[act.x][act.y] || wall_vert[act.x + 1][act.y])
                return false;
            wall_vert[act.x][act.y] = wall_vert[act.x + 1][act.y] = true;
            bool res = isConnected();
            wall_vert[act.x][act.y] = wall_vert[act.x + 1][act.y] = false;
            return res;
        } else
            return false;
    }

    // 操作の候補
    vector<Act> candidateActs() {
        vector<Act> res;
        rep(i, 4) {
            if (isOK(Act{0, int(i), 0}))
                res.push_back(Act{0, int(i), 0});  // 隣接マスへ移動
        }
        rep(i, 9) rep(j, 9) {
            if (isOK(Act{1, int(i), int(j)}))
                res.push_back(Act{1, int(i), int(j)});  // 水平方向の壁
            if (isOK(Act{2, int(i), int(j)}))
                res.push_back(Act{2, int(i), int(j)});  // 垂直方向の壁
        }
        return res;
    }

    // 操作を実行する
    bool applyAct(Act act, bool check = true) {
        if (check && !isOK(act)) return false;
        if (act.type == 0) {  // 隣接マスへ移動
            X[turn] += dx[act.x];
            Y[turn] += dy[act.x];
            if (C[X[turn]][Y[turn]]) {
                score[turn]++;
                C[X[turn]][Y[turn]] = false;
            }
        } else if (act.type == 1) {  // 水平方向の壁
            wall_hrz[act.x][act.y] = wall_hrz[act.x][act.y + 1] = true;
            wall_used[turn]++;
        } else {  // 垂直方向の壁
            wall_vert[act.x][act.y] = wall_vert[act.x + 1][act.y] = true;
            wall_used[turn]++;
        }
        // ゲームが終了しているかの判定
        bool flag = false;
        rep(i, 9) rep(j, 9) {
            if (C[i][j]) flag = true;
        }
        if (!flag) is_finished = true;
        acts.push_back(act);

        // 交代
        turn ^= 1;
        turn_num++;
        return true;
    }

    // スコアや盤面を出力する（デバッグ用）
    void printBoard() {
        cerr << "Score: " << score[0] << " " << score[1] << "\n"
             << "Wall counter: " << wall_used[0] << " " << wall_used[1] << endl
             << endl;
        rep(i, 9) {
            rep(j, 9) {
                if (i == X[0] && j == Y[0] && i == X[1] && j == Y[1])
                    cerr << " AB";
                else if (i == X[0] && j == Y[0])
                    cerr << " A ";
                else if (i == X[1] && j == Y[1])
                    cerr << " B ";
                else {
                    if (C[i][j])
                        cerr << " # ";
                    else
                        cerr << " . ";
                }
                if (j < 8) cerr << (wall_vert[i][j] ? " | " : "   ");
            }
            cerr << endl;
            if (i != 8) {
                rep(j, 9) {
                    if (j) cerr << "   ";
                    cerr << (wall_hrz[i][j] ? "---" : "   ");
                }
            }
            cerr << endl;
        }
        cerr << endl;
    }
    Game()
        : C(9, vector<bool>(9)),
          wall_hrz(9, vector<bool>(9)),
          wall_vert(9, vector<bool>(9)),
          X(2),
          Y(2),
          wall_used(2),
          score(2) {
        wall_used[0] = wall_used[1] = 0;
        score[0] = score[1] = 0;
        X[0] = 8, X[1] = 0, Y[0] = Y[1] = 4;
    }

    vector<vector<int>> getDistance(int startx, int starty) {
        queue<pair<int, int>> que;
        que.emplace(startx, starty);

        vector<vector<int>> dist(9, vector<int>(9, -1));
        dist[startx][starty] = 0;

        while (!que.empty()) {
            int nx = que.front().first;
            int ny = que.front().second;
            que.pop();
            if (nx != 0 && !wall_hrz[nx - 1][ny]) {
                if (dist[nx - 1][ny] == -1) {
                    dist[nx - 1][ny] = dist[nx][ny] + 1;
                    que.emplace(nx - 1, ny);
                }
            }
            if (ny != 8 && !wall_vert[nx][ny]) {
                if (dist[nx][ny + 1] == -1) {
                    dist[nx][ny + 1] = dist[nx][ny] + 1;
                    que.emplace(nx, ny + 1);
                }
            }
            if (nx != 8 && !wall_hrz[nx][ny]) {
                if (dist[nx + 1][ny] == -1) {
                    dist[nx + 1][ny] = dist[nx][ny] + 1;
                    que.emplace(nx + 1, ny);
                }
            }
            if (ny != 0 && !wall_vert[nx][ny - 1]) {
                if (dist[nx][ny - 1] == -1) {
                    dist[nx][ny - 1] = dist[nx][ny] + 1;
                    que.emplace(nx, ny - 1);
                }
            }
        }

        return dist;
    }

    int getScore(int t) {
        int result = 0;
        int mn = 1e9;

        auto dist = getDistance(X[t], Y[t]);

        rep (i, 9) rep (j, 9) {
            if (C[i][j]) {
                int val = 0;
                if(i != 0 && !wall_hrz[i - 1][j])val++;
                if(j != 8 && !wall_vert[i][j])val++;
                if(i != 8 && !wall_hrz[i][j])val++;
                if(j != 0 && !wall_vert[i][j - 1])val++;
                result -= dist[i][j] * val;
                chmin(mn, dist[i][j]);
            }
        }

        result -= mn * 50;

        result += score[t] * 100000;

        return result;
    }

    int getEval() {
        if (turn_num < 120) {
            int result = 0;

            result -= getScore(turn);
            result += getScore(!turn);

            return result;
        }
        auto dist = getDistance(X[!turn], Y[!turn]);
        int mn = 1e9;
        rep (i, 9) rep (j, 9) {
            if (C[i][j]) chmin(mn, dist[i][j]);
        }
        return -mn;
    }
};

// 処理に掛かっている合計時間
double tim_sum;

int alpha_beta(Game game,int alpha,int beta,int dep){
    if(dep == 0)return game.getEval();
    // debug(alpha,beta,dep);
    auto acts = game.candidateActs();
    // 
    int res = game.turn == game.myturn ? -inf : inf;
    bool my = game.turn == game.myturn;
    for(auto act : acts){
        Game nxt = game;
        nxt.applyAct(act);
        if(my){
            int sc = alpha_beta(nxt,alpha,beta,dep - 1);
            if(beta <= sc)return sc;
            if(chmax(res,sc)){
                chmax(alpha,sc);
            }

        }
        else{
            int sc = alpha_beta(nxt,alpha,beta,dep - 1);
            if(alpha >= sc)return sc;
            if(chmin(res,sc)){
                chmin(beta,sc);
            }
        }
    }
    return res;
}

// 自分のターンになったら呼ばれるので、操作を選ぶ。先手なら game.turn=0,
// 後手なら game.turn=1 の状態で呼ばれる
Act choose(Game game) {
    // 時間計測用
    chrono::system_clock::time_point clk = chrono::system_clock::now();

    vector<Act> acts = game.candidateActs();
    int mx = -1e9;
    Act best_act;
    for (Act act : acts) {
        cerr<<"koko\n";
        Game new_game = game;
        new_game.applyAct(act);
        if(chmax(mx,alpha_beta(new_game,-inf,inf,2))){
            best_act = act;
        }
        // if(chmax(mx,new_game.getEval())){
        //     best_act = act;
        // }
    }

    // 時間計測用
    tim_sum += static_cast<double>(chrono::duration_cast<chrono::microseconds>(
                                       chrono::system_clock::now() - clk)
                                       .count() /
                                   1000000.0);
    return best_act;
}
int main() {
    string s;
    cin >> s;
    Game game;
    rep(i, 9) {
        rep(j, 9) {
            char c;
            cin >> c;
            if (c == '#')
                game.C[i][j] = true;
            else
                game.C[i][j] = false;
        }
    }
    int turn = 0, myturn = (s == "First" ? 0 : 1);
    game.myturn = myturn;

    while (1) {
        if (turn == myturn) {
            Act act = choose(game);
            game.applyAct(act);
            if (!act.type) {
                cout << act.type << " " << act.x << endl;
            } else {
                cout << act.type << " " << act.x << " " << act.y << endl;
            }
        } else {
            int t;
            cin >> t;
            if (!t) {
                int x;
                cin >> x;
                game.applyAct(Act{0, x, 0});
            } else if (t <= 2) {
                int x, y;
                cin >> x >> y;
                game.applyAct(Act{t, x, y});
            } else {
                return 0;
            }
        }
        // デバッグ用
        game.printBoard();
        turn ^= 1;
    }
}
